import { reactive } from "vue";

const toasts = reactive([]);
let toastCounter = 0;

const normalizeToastType = (type) => {
  if (type === "success" || type === "error" || type === "warning" || type === "info") return type;
  return "info";
};

export const pushToast = ({
  title = "Pemberitahuan",
  message = "",
  type = "info",
  duration = 3200,
} = {}) => {
  const normalizedDuration = Math.max(0, Number(duration) || 0);
  const nextToast = {
    id: `${Date.now()}-${toastCounter += 1}`,
    title,
    message,
    type: normalizeToastType(type),
    duration: normalizedDuration,
  };

  toasts.unshift(nextToast);

  if (normalizedDuration > 0) {
    window.setTimeout(() => {
      dismissToast(nextToast.id);
    }, normalizedDuration);
  }

  return nextToast.id;
};

export const dismissToast = (toastId) => {
  const targetIndex = toasts.findIndex((item) => item.id === toastId);
  if (targetIndex >= 0) {
    toasts.splice(targetIndex, 1);
  }
};

export const useToast = () => ({
  toasts,
  pushToast,
  dismissToast,
});
